@extends('layouts.app') @section('title',($record?'Edit ':'Add ').$config['singular']) @section('content')<div class="mb-4"><a href="{{ route('admin.resources.index',$module) }}" class="text-decoration-none"><i class="bi bi-arrow-left"></i> Back</a><h2 class="fw-bold mt-2">{{ $record?'Edit':'Add' }} {{ $config['singular'] }}</h2></div><form method="POST" enctype="multipart/form-data" action="{{ $record?route('admin.resources.update',[$module,$record->id]):route('admin.resources.store',$module) }}">@csrf @if($record)@method('PUT')@endif<div class="card"><div class="card-body p-4"><div class="row g-4">@foreach($config['fields'] as $name=>$type)@php [$kind,$values]=array_pad(explode(':',$type,2),2,null);$current=old($name,$record?->{$name}); @endphp<div class="{{ $kind==='textarea'?'col-12':'col-md-6' }}"><label class="form-label fw-semibold">{{ str($name)->replace('_',' ')->title() }}</label>@if($kind==='textarea')<textarea class="form-control" rows="4" name="{{ $name }}">{{ $current }}</textarea>@elseif($kind==='select')<select class="form-select" name="{{ $name }}">@foreach(explode(',',$values) as $option)<option value="{{ $option }}" @selected($current===$option)>{{ str($option)->replace('_',' ')->title() }}</option>@endforeach</select>@elseif($kind==='relation')<select class="form-select" name="{{ $name }}"><option value="">Unassigned</option>@foreach($options[$values]??[] as $id=>$label)<option value="{{ $id }}" @selected((string)$current===(string)$id)>{{ $label }}</option>@endforeach</select>@elseif($kind==='boolean')<input type="hidden" name="{{ $name }}" value="0"><div class="form-check form-switch pt-2"><input class="form-check-input" type="checkbox" name="{{ $name }}" value="1" @checked($current??true)></div>@else<input class="form-control" type="{{ $kind }}" name="{{ $name }}" value="{{ $kind==='password'?'':$current }}" step="{{ $kind==='number'?'any':'' }}" {{ (!$record&&$kind==='password')?'required':'' }}>@endif @error($name)<small class="text-danger">{{ $message }}</small>@enderror</div>@endforeach</div></div><div class="card-footer bg-transparent text-end p-3"><a class="btn btn-light" href="{{ route('admin.resources.index',$module) }}">Cancel</a><button class="btn btn-primary px-4">Save {{ $config['singular'] }}</button></div></div></form>@endsection
